    // ── Security ──
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // ── Appearance ──
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private static readonly string[] _availableLanguages =
        ["en", "es", "fr", "de", "ja", "zh", "pt", "ko"];

    private static readonly Dictionary<string, string> _languageLabels = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文",
        ["pt"] = "Português",
        ["ko"] = "한국어",
    };

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
        _loading = false;
    }

    private async Task LoadAllSettingsAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appearTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, secTask, appearTask);

        ApplyProfile(await profileTask);
        ApplyNotifications(await notifsTask);
        ApplySecurity(await secTask);
        ApplyAppearance(await appearTask);
    }

    // ── Profile helpers ──

    private void ApplyProfile(UserProfile p)
    {
        _profileOriginal = p;
        _profileName = p.DisplayName;
        _profileEmail = p.Email;
        _profileBio = p.Bio;
        _profileAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_profileName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _profileOriginal = updated;
            ShowStatus("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowStatus($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    private void DiscardProfileChanges()
    {
        if (_profileOriginal is not null)
            ApplyProfile(_profileOriginal);
    }

    // ── Notification helpers ──

    private void ApplyNotifications(NotificationPrefs n)
    {
        _emailNotifications = n.EmailNotifications;
        _pushNotifications = n.PushNotifications;
        _weeklyDigest = n.WeeklyDigest;
        _channels = n.MutedChannels
            .Select(c => new ChannelMuteState(c, true))
            .ToList();

        // Ensure we also show unmuted channels; the service only returns muted ones,
        // so we add well-known defaults if missing.
        var knownChannels = new[] { "general", "announcements", "engineering", "design", "marketing", "random" };
        foreach (var ch in knownChannels)
        {
            if (!_channels.Any(c => c.Name == ch))
                _channels.Add(new ChannelMuteState(ch, false));
        }

        _channels = _channels.OrderBy(c => c.Name).ToList();
    }

    private void ToggleChannelMute(int index)
    {
        var ch = _channels[index];
        _channels[index] = ch with { Muted = !ch.Muted };
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowStatus("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowStatus($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    // ── Security helpers ──

    private void ApplySecurity(SecuritySettings s)
    {
        _security = s;
        _twoFactorEnabled = s.TwoFactorEnabled;
    }

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowStatus("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowStatus("New password and confirmation do not match.", isError: true);
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _changePasswordExpanded = false;
            ShowStatus("Password updated successfully.");
        }
        catch (Exception ex)
        {
            ShowStatus($"Password change failed: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    private void RequestRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            // Reload security settings to refresh session list
            var updated = await SettingsService.GetSecuritySettingsAsync();
            ApplySecurity(updated);
            ShowStatus("Session revoked.");
        }
        catch (Exception ex)
        {
            ShowStatus($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _revoking = false;
            _sessionToRevoke = null;
        }
    }

    // ── Appearance helpers ──

    private void ApplyAppearance(AppearanceSettings a)
    {
        _theme = a.Theme;
        _fontSize = a.FontSize;
        _language = a.Language;
        _compactMode = a.CompactMode;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowStatus("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowStatus($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    // ── Utility ──

    private void ShowStatus(string message, bool isError = false)
    {
        _statusMessage = message;
        _statusIsError = isError;
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem",
    };

    // ── Render fragments ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section>
            <h4 class="section-heading">Profile</h4>
            <p class="text-muted">Manage your public profile information.</p>

            <div class="card settings-card">
                <div class="card-body">
                    <!-- Avatar preview -->
                    <div class="avatar-area mb-4">
                        <div class="avatar-preview">
                            @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                            {
                                <img src="@_profileAvatarUrl" alt="Avatar" />
                            }
                            else
                            {
                                <span class="avatar-placeholder">👤</span>
                            }
                        </div>
                        <div class="avatar-url-display">
                            <label class="form-label">Avatar URL</label>
                            <input type="url" class="form-control" @bind="_profileAvatarUrl"
                                   placeholder="https://example.com/avatar.png" />
                        </div>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Display Name</label>
                        <input type="text" class="form-control" @bind="_profileName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_profileEmail" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="4" @bind="_profileBio"></textarea>
                    </div>

                    <div class="d-flex gap-2">
                        <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Save Changes
                        </button>
                        <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">
                            Discard Changes
                        </button>
                    </div>
                </div>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section>
            <h4 class="section-heading">Notifications</h4>
            <p class="text-muted">Choose how and when you want to be notified.</p>

            <div class="card settings-card mb-4">
                <div class="card-body">
                    <h6 class="card-subtitle mb-3">Notification Channels</h6>

                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="emailNotif"
                               @bind="_emailNotifications" />
                        <label class="form-check-label" for="emailNotif">Email Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="pushNotif"
                               @bind="_pushNotifications" />
                        <label class="form-check-label" for="pushNotif">Push Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="weeklyDigest"
                               @bind="_weeklyDigest" />
                        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                    </div>
                </div>
            </div>

            <div class="card settings-card mb-4">
                <div class="card-body">
                    <h6 class="card-subtitle mb-3">Muted Channels</h6>
                    <div class="channels-list">
                        @for (int i = 0; i < _channels.Count; i++)
                        {
                            var idx = i;
                            var ch = _channels[idx];
                            <div class="form-check mb-2">
                                <input class="form-check-input" type="checkbox" id="@($"ch-{idx}")"
                                       checked="@ch.Muted" @onchange="() => ToggleChannelMute(idx)" />
                                <label class="form-check-label" for="@($"ch-{idx}")">
                                    #@ch.Name
                                </label>
                            </div>
                        }
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section>
            <h4 class="section-heading">Security</h4>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>

            <!-- Change Password -->
            <div class="card settings-card mb-4">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center">
                        <h6 class="card-subtitle mb-0">Change Password</h6>
                        <button class="btn btn-sm btn-outline-secondary"
                                @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                            @(_changePasswordExpanded ? "Collapse" : "Expand")
                        </button>
                    </div>

                    @if (_changePasswordExpanded)
                    {
                        <div class="mt-3">
                            <div class="mb-3">
                                <label class="form-label">Current Password</label>
                                <input type="password" class="form-control" @bind="_currentPassword" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">New Password</label>
                                <input type="password" class="form-control" @bind="_newPassword" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Confirm New Password</label>
                                <input type="password" class="form-control" @bind="_confirmPassword" />
                            </div>
                            <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Update Password
                            </button>
                        </div>
                    }
                </div>
            </div>

            <!-- Two-Factor Authentication -->
            <div class="card settings-card mb-4">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="card-subtitle mb-1">Two-Factor Authentication</h6>
                            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                                @(_twoFactorEnabled ? "Enabled" : "Disabled")
                            </span>
                            @if (_security?.LastPasswordChange is not null)
                            {
                                <small class="text-muted ms-2">
                                    Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                                </small>
                            }
                        </div>
                        <div class="form-check form-switch mb-0">
                            <input class="form-check-input" type="checkbox" id="twoFactor"
                                   @bind="_twoFactorEnabled" />
                        </div>
                    </div>
                </div>
            </div>

            <!-- Active Sessions -->
            <div class="card settings-card">
                <div class="card-body">
                    <h6 class="card-subtitle mb-3">Active Sessions</h6>

                    @if (_security?.Sessions is { Count: > 0 })
                    {
                        <div class="table-responsive">
                            <table class="table table-hover mb-0">
                                <thead>
                                    <tr>
                                        <th>Device</th>
                                        <th>Location</th>
                                        <th>Last Active</th>
                                        <th></th>
