                                            </td>
                                        </tr>
                                    }
                                </tbody>
                            </table>
                        </div>
                    }
                    else
                    {
                        <p class="text-muted mb-0">No active sessions found.</p>
                    }
                </div>
            </div>
        </section>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section>
            <h4 class="section-heading">Appearance</h4>
            <p class="text-muted">Customize how the application looks and feels.</p>

            <div class="card settings-card mb-4">
                <div class="card-body">
                    <!-- Theme -->
                    <h6 class="card-subtitle mb-3">Theme</h6>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var t in new[] { "Light", "Dark", "System" })
                        {
                            var theme = t;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>

                    <!-- Font Size -->
                    <h6 class="card-subtitle mb-3">Font Size</h6>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var fs in new[] { "Small", "Medium", "Large" })
                        {
                            var size = fs;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>

                    <!-- Language -->
                    <h6 class="card-subtitle mb-3">Language</h6>
                    <div class="mb-4" style="max-width: 280px;">
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _availableLanguages)
                            {
                                <option value="@lang">@_languageLabels[lang]</option>
                            }
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="form-check form-switch mb-4">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="card settings-card mb-4">
                <div class="card-body">
                    <h6 class="card-subtitle mb-3">Preview</h6>
                    <div class="appearance-preview @(_theme == "Dark" ? "preview-dark" : "preview-light")"
                         style="font-size: @PreviewFontSize; @(_compactMode ? "padding: 0.75rem;" : "padding: 1.5rem;")">
                        <div class="preview-header">
                            <strong>Dashboard</strong>
                            <span class="preview-lang-badge">@_languageLabels.GetValueOrDefault(_language, _language)</span>
                        </div>
                        <p class="preview-body">
                            This is a preview of your selected appearance settings.
                            The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                            and compact mode is <strong>@(_compactMode ? "on" : "off")</strong>.
                        </p>
                        <div class="preview-actions">
                            <span class="preview-btn primary">Primary Action</span>
                            <span class="preview-btn secondary">Secondary</span>
                        </div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </section>
    };
}
"}

